  1→import React, { useState } from 'react';
  2→import { ScrollView, View, Pressable } from 'react-native';
  3→import {
  4→  Text,
  5→  Box,
  6→  SeparatorHorizontal,
  7→  CardVehicleTags,
  8→  Header,
  9→} from '@semparar/design-system-app';
 10→import type { Meta, StoryObj } from 'storybook/internal/types';
 11→import type { SDUIScreen } from '../services/sdui/models';
 12→import ScreenRenderer from '../services/sdui/renderer/ScreenRenderer';
 13→import { registerAllAdapters } from '../services/sdui/adapters';
 14→import { useSDUIJsonEditor } from '../../.storybook/addons/json-editor';
 15→import {
 16→  voucherListLoaded,
 17→  voucherListEmpty,
 18→  voucherListFiltered,
 19→} from '../services/sdui/mocks';
 20→
 21→registerAllAdapters();
 22→
 23→type ViewState = 'list' | 'empty' | 'filtered';
 24→
 25→const SCREENS: Record<ViewState, SDUIScreen> = {
 26→  list: voucherListLoaded,
 27→  empty: voucherListEmpty,
 28→  filtered: voucherListFiltered,
 29→};
 30→
 31→function ViewToggle({
 32→  selected,
 33→  onSelect,
 34→}: {
 35→  selected: ViewState;
 36→  onSelect: (v: ViewState) => void;
 37→}) {
 38→  const labels: Record<ViewState, string> = {
 39→    list: 'List (6)',
 40→    empty: 'Empty',
 41→    filtered: 'Filtered',
 42→  };
 43→
 44→  return (
 45→    <View style={{ flexDirection: 'row', gap: 8, marginBottom: 16 }}>
 46→      {(['list', 'empty', 'filtered'] as const).map(v => (
 47→        <Pressable
 48→          key={v}
 49→          onPress={() => onSelect(v)}
 50→          style={{
 51→            paddingHorizontal: 16,
 52→            paddingVertical: 8,
 53→            borderRadius: 20,
 54→            backgroundColor: selected === v ? '#6B2FBE' : '#E8E0F0',
 55→          }}
 56→        >
 57→          <Text
 58→            type="paragraphMDM"
 59→            color={selected === v ? 'LIGHT_BASE_01' : 'INTENSE_COLOR_05'}
 60→          >
 61→            {labels[v]}
 62→          </Text>
 63→        </Pressable>
 64→      ))}
 65→    </View>
 66→  );
 67→}
 68→
 69→function VoucherListDemo() {
 70→  const [view, setView] = useState<ViewState>('list');
 71→  const screen = useSDUIJsonEditor(SCREENS[view]);
 72→
 73→  return (
 74→    <ScrollView style={{ flex: 1 }}>
 75→      <View style={{ padding: 24, maxWidth: 420 }}>
 76→        <Text type="headingMDL" mb="nano">
 77→          SDUI: Meus Vouchers
 78→        </Text>
 79→        <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
 80→          Renders the voucher list from JSON via SDUI engine. Cards use context
 81→          interpolation — edit the JSON to change data dynamically.
 82→        </Text>
 83→
 84→        <ViewToggle selected={view} onSelect={setView} />
 85→
 86→        <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm">
 87→          <ScreenRenderer screen={screen} />
 88→        </Box>
 89→      </View>
 90→    </ScrollView>
 91→  );
 92→}
 93→
 94→const REAL_SCREEN_ORDERS = (voucherListLoaded.context.orders as Record<string, string>[]).map(o => ({
 95→  icon: String(o.icon),
 96→  desc: String(o.description),
 97→  pts: String(o.points),
 98→  date: String(o.date),
 99→  status: String(o.status),
100→  tag: String(o.tag),
101→}));
102→
103→function RealScreenPreview() {
104→  return (
105→    <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
106→      <Header
107→        title="Meus pedidos"
108→        iconLeft="icon-back"
109→        hideLeftIcon={false}
110→        onBack={() => {}}
111→        iconRight="icon-filter-settings"
112→        onPressRight={() => {}}
113→      />
114→      {REAL_SCREEN_ORDERS.map((item, idx) => (
115→        <Box key={idx} ml="middle" mr="middle" mt="smaller">
116→          <CardVehicleTags
117→            vehicleName={item.desc}
118→            icon={item.icon as any}
119→            title="Valor em pontos"
120→            titleDescription={item.pts}
121→            date="Data do resgate"
122→            dateNumber={item.date}
123→            statusTitle="Status do pedido"
124→            status={item.status}
125→            ghostButtonText="Exibir detalhes"
126→            onGhostButtonPress={() => {}}
127→            type="extended"
128→            typeTag={item.tag as any}
129→            version="2.0"
130→          />
131→        </Box>
132→      ))}
133→    </Box>
134→  );
135→}
136→
137→function SideBySideComparison() {
138→  const screen = useSDUIJsonEditor(voucherListLoaded);
139→
140→  return (
141→    <ScrollView style={{ flex: 1 }}>
142→      <View style={{ padding: 24 }}>
143→        <Text type="headingMDL" mb="nano">
144→          Side-by-Side: Real Screen vs SDUI
145→        </Text>
146→        <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
147→          Left: traditional React components with hardcoded data. Right: same
148→          visual result rendered entirely from JSON via the SDUI engine.
149→        </Text>
150→
151→        <View style={{ flexDirection: 'row', gap: 24 }}>
152→          <View style={{ flex: 1, maxWidth: 420 }}>
153→            <Text type="subtitleXXL" mb="nano" align="center">
154→              Real Screen (SP_0004.6)
155→            </Text>
156→            <Box br="sm" style={{ overflow: 'hidden' }}>
157→              <RealScreenPreview />
158→            </Box>
159→          </View>
160→
161→          <View style={{ flex: 1, maxWidth: 420 }}>
162→            <Text type="subtitleXXL" mb="nano" align="center">
163→              SDUI from JSON
164→            </Text>
165→            <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm">
166→              <ScreenRenderer screen={screen} />
167→            </Box>
168→          </View>
169→        </View>
170→
171→        <SeparatorHorizontal mv="xs" />
172→
173→        <Box pd="innerSmall" bgColor="BRAND_COMPLEMENT_02" br="sm">
174→          <Text type="paragraphMDM" mb="xxxs">
175→            Key difference
176→          </Text>
177→          <Text type="bodyMD" color="INTENSE_COLOR_03">
178→            The left column requires code changes to update content. The right
179→            column renders from JSON — the backend can change card data, add new
180→            cards, or switch statuses without any frontend deploy.
181→          </Text>
182→        </Box>
183→      </View>
184→    </ScrollView>
185→  );
186→}
187→
188→const meta: Meta = {
189→  title: 'SDUI/Voucher List',
190→  component: VoucherListDemo,
191→};
192→
193→export default meta;
194→
195→type Story = StoryObj<typeof meta>;
196→
197→export const Demo: Story = {
198→  render: () => <VoucherListDemo />,
199→};
200→
201→export const Comparison: Story = {
202→  name: 'Side-by-Side Comparison',
203→  render: () => <SideBySideComparison />,
204→};
